sp_widget.client_script:
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
function ($scope,$http, spUtil,$rootScope, $interval) {
	var c = this;
	var CONST_MINUTES_IN_MS = 1000 * 60;
	var CONST_NINETY_SECONDS = 1.5 * CONST_MINUTES_IN_MS;
	var refreshPromise;

	// this is to prevent a post back in the $on when this
	// widget pushed the broadcast notification
	var changedByThisWidgetId = false;
	if (!c.data.table)
		return;

/* STRY0081697 - removed the record watcher
	// added the update to reload as it wasn't reloading the count
	spUtil.recordWatch($scope, c.data.table, c.data.filter, function(){
		// DFCT0011188 - reload to get latest count
		spUtil.update($scope);
	});
*/
	// STRY0114448 - adding additional parameters
	c.params = {
		'table' : c.data.table,
		'filter' : c.data.filter,
		'sp_page_dv' : c.options.sp_page_dv,
		'title' : c.data.title,
		'd' : c.data.d,
		'o' : c.data.o,
		'field_list': c.data.field_list,
		'glyph' : c.options.glyph
	};

	// when the users selects this count,
	// broadcast to the data table and other counts
	c.selectCount = function(){
			_broadCastFitlerChange();
			$scope.data.filterChanged=true;
			spUtil.update($scope);
	}

	// when the user selects an item from the dynamic filter dropdown
	// reload the count info and broadcast the selection
	c.setDynamicFilter = function(filter){
		// update the dynamic filter
		$scope.data.tasker_filter_id = filter.tasker_filter_id;
		$scope.data.table = filter.table;
		$scope.data.filter = filter.filter;
		$scope.data.title = filter.filter_label;
		$scope.data.o = filter.o;
		$scope.data.d = filter.d;
		$scope.data.count = filter.count;
		$scope.data.filterChanged=true;
		spUtil.update($scope).then(function(){
			_broadCastFitlerChange();
		});
	}

	function _broadCastFitlerChange(){
		// prevents post back when broadcast from this count item
		changedByThisWidgetId = true;

			// set the parameters for the view
			c.params.tasker_filter_id = c.data.tasker_filter_id;
			c.params.filter = c.data.filter;
			c.params.sp_page_dv = c.data.view_all_page;
			c.params.table = c.data.table;
			c.params.title = c.data.title;
			c.params.d = c.data.d;
			c.params.o = c.data.o;
			c.params.field_list = c.data.field_list;	
		$rootScope.$broadcast('countPanelClicked', c.params);			
	}

	$rootScope.$on('countPanelClicked', function(e, parms) {
		// prevents postback when this item sent broadcast
		if(!changedByThisWidgetId){
			c.data.selectedFilterTitle = parms.title;
			c.data.isFilterSelected = (c.data.selectedFilterTitle==c.data.title);			
		}
		// reset to false after skipping local update
		changedByThisWidgetId = false;
	});

	// STRY0081697
	$scope.refreshBanner = function(){
		if(refreshPromise && refreshPromise!=undefined){
			return;
		}
		refreshPromise = $interval(function(){
			// add logic here to determine if we keep running
			// for example, if we added a refresh button, we would want to cancel this, then start another one
			// or, if the user left the screen open, then we might want to cancel after a certain number of refreshes
			$scope.data.refreshMenuCounts = true;
			spUtil.update($scope).then(function(){
				// do anything you need to do here after receiving back
			});			
		}, CONST_NINETY_SECONDS);
	}

	$scope.stopRefresh = function() {
		if (refreshPromise && (refreshPromise!=undefined)) {
			$interval.cancel(refreshPromise);
			refreshPromise = undefined;
		}
	};

	$scope.$on('$destroy', function() {
		// Make sure that the interval is destroyed too
		$scope.stopRefresh();
	});

	// start the interval
	$scope.refreshBanner();

}

sp_widget.css:
/* this class is used to set focus.  
It is the same style as the servicenow btn:focus 
TODO - We may want to move into global class*/




/* set the hover boarder and background color 
- NEED here as when coming from stylesheet, not overriding widget */
.dtech-filter-btn:hover{
  background-color: rgba(217, 237, 247, 1);
} 

/* font to make the count number bolder and align left */
.dtech-font-count {
  color: rgba(0, 0, 0, 1);
  font-size: 16px;
  font-weight: 600;
  text-align: left;
} 

/* sets disabled count */
.dtech-font-count:disabled {
  color: rgba(175, 188, 194, 1);
} 

/* sets the font for the text of the count */
.dtech-font-description {
  color: rgba(117, 117, 117, 1);
  font-size: 14px;
  font-weight: 400;
} 

/* this comes over from portal filter */
.dtech-border-none {
  border:none;
}

.dtech-dropdown-header {
  /* color: #3A3F51; */
  font-size: 14px;
  font-weight: 500;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added padding */
  padding: 10px 20px;
}

/* Bootstrap 3.3.6 default: .dropdown-menu > li > a:hover, .dropdown-menu > li > a:focus { */
/* this overrides the defaults for dropdown items for the filter menu*/
.dropdown-menu > li > ul > li > a:hover, .dropdown-menu > li > ul > li > a:focus {
  text-decoration: none;
  color: #2f3342;
  background-color: #f5f5f5;
}

/* this sets the color for the count badge for filter items*/
.badge {
  background-color: $banner-count-bg;
  color: $banner-count-text;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added height for badge */
  height: 20px;
}
/* Must be a descendant of the class dtech-box */
.dtech-box .dtech-flex-space-15px {
  width: 15px;
}
.dtech-dropdown-menu-align-right{
  right: 0;
  left: auto;
}

.dtech-filter-menu {
  /*
  2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added box-shadow
  Note using rgba, (Red Green Blue Alpha) that controls the opacity or transparency 
  that follows the same percentage scheme: 0% represents absolute transparency and 100% represents absolute opacity 
  */
  box-shadow: 0 6px 12px rgba(0, 0, 0, .25); /* yields: box-shadow: 0 6px 12px rgb(0 0 0 / 25%); */
  right: 45px; /* aligns with right side of the count control*/
  left: auto; /* allows width to grow as needed */


}

.dtech-margin-right-5px {
  margin-right: 5px;
}

.dtech-inline-start {
  padding-left: 15px;
}

.dtech-pad-top-5px {
  padding: 5px 0;
}

.dtech-scrollable-menu {
  height: auto;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Changed max-height, was 500 */
  max-height: 700px;
  overflow-x: hidden;
}

.dtech-subMenu {
  list-style-type: none;
  padding: 2px 0;
}

.dtech-subMenu-item {
  color: #3A3F51;
  font-size: 14px;
  font-weight: normal;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: COUNT
// COMPANY: DISCOVER TECHNOLOGIES
// 2.7.1 | 2021-11-26 | raj  | STRY0114448 - Modern Portal Filter- Selecting any Widget Filters will set that filter as Default
//                                         Changes made in Server Scripot, Client Script
// 2.8   | 2022-05-21 | raj  | STRY0121805 - Homepage UI Update- New Design for Colorful Filter and "Show More Filters" dropdown
//                             STRY0121807 - Homepage- "My Tasks" Landing Page
//                             STRY0121811 - Homepage UI Update- Navigation Bar Revamp and add access points for "My Tasks" and "My OU's Tasks"
//                                         Changes made in Server Scripot, Client controller, HTML and CSS
// 2.8   | 2022-08-18 | raj  | DFCT0011140 - Record watcher: "Warning Icon" &  "Duration icon"  should NOT trigger the visual warning indicator on load. (Taker Type "Approval)
//																					Changes in client script
// 2.8   | 2022-08-18 | raj  | DFCT0011188 - Record watcher: New Task  assignment, does NOT display  for the" Assigned members" unless page is refreshed
//																					Changes in client script
// 2.8.3 | 2023-07-14 | raj | DFCT0011947 - "Open Task by My OU to Others" & "Tasks by My OU to Others" should NOT display large query on the Tasker Portal page
//																			In Server Script only
// 2.8.3HF | 2023-09-24 | raj | STRY0081697 - Banner Notification re-group banners to minimize performance load time
//											Changes in Client Controller and Server Script 
//											Added $interval to client script function parameters 
//
//------------------------------------------------------------------------------------------------------------------------
(function ($sp, input, data, options, gs) {
	// declare globally so they are loaded once in the main function
	var tsss;
	var OUsWhereIamAMember;
	var OUsWhereIamAMemberAdmin;

	main();

	function main(){
		// STRY0101803 - load user preferences object for use when opening forms
		// only load this one time
		tsss =  new x_153465_discovert.tasking_System_Settings_Scripts();
		OUsWhereIamAMember = tsss.getOUsWhereIamAMember();
		// DFCT0010732
		OUsWhereIamAMemberAdmin = tsss.getMyOUMemberAdmins();

		var page_filter;
		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('tasker_count');

		if(input){
			// if the filter changed, save it back
			if(input.filterChanged){
				var objDefaultMainFilter = {displayValue:input.title, value:input.tasker_filter_id};
				taskWidgetIconsAndMessage.savePreferenceUserDefaultMainFilter(input.page_filter, objDefaultMainFilter);
			}
			// STRY0081697
			if(input.refreshMenuCounts){
				// if refreshing count, just refresh count and return
				data.filter = input.filter;
				data.table = input.table;
				data.count = _getDataCount();
				return;
			}

		}

		// this is used to load the the dynamic fitler text
		// when the default filters is in the dropdown list
		data.filterInDynamicList = false;
		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);

		// load filter page
		data.page_filter = data.settings.userDefaultLandingPage;

		// load currently selected fitler
		data.selectedFilterTitle = data.settings.userDefaultMainFilter.displayValue;
		data.selectedFilterId = data.settings.userDefaultMainFilter.value;

		// this function loads the drop down list based on the page
		// it also determines if the selected fitler is in the current
		/// dropdown so the count can be loaded
		_loadDynamicFilter(data.selectedFilterId);

		// loads the count filter for this count item
		_loadCountFilter(data.page_filter, data.selectedFilterId);
		// isFilterSelected is true when this item is currently loaded
		// in the data table list
		// data.title is set in the load count fitler function. 
		// don't move this line before that function
		data.isFilterSelected = data.selectedFilterId==data.tasker_filter_id || undefined;

		if (!data.table)
			return;

		// NOTE: when we have icons for all fitlers, this would go below
		if(options.icon){
			data.iconName = _getIcon(options.icon);
		}

		// load the count for this item based on filter 
		data.count = _getDataCount();

	}

	// load the fitler based on the page
	function _loadCountFilter(page_filter, selected_filter_id){
		var filterParams;
		var filterId;
		if(data.is_dynamic_filter && 
			 data.filterInDynamicList &&
			 selected_filter_id){
			filterParams = _loadFilterParams(selected_filter_id);
		}
		// this if statement will be true when
		// the fitler is not the dynamic filter and no fitler was saved
		if(filterParams == undefined){
			if(page_filter == 'my_task_home_page' && 
				 options.tasker_filter_my_task_filter +'' != ''){
				filterId = options.tasker_filter_my_task_filter;
				filterParams = _loadFilterParams(options.tasker_filter_my_task_filter)
			} else if(page_filter == 'my_ous_tasks_home_page' &&
								options.my_ous_tasks_home_page + '' != ''){
				filterId = options.my_ous_tasks_home_page;
				filterParams = _loadFilterParams(options.tasker_filter_my_ou_s_task_filter);
			}
		}

		// pull from the hard coded values
		if(filterParams){
			data.tasker_filter_id = filterParams.tasker_filter_id;
			data.table = filterParams.table;
			data.filter = filterParams.filter || 'sys_id!=NULL';
			data.title = filterParams.title;
			data.o = filterParams.order_by || 'created';
			data.d = filterParams.order_direction || 'DESC';
			data.field_list = filterParams.field_list || '';
		}else{
			data.tasker_filter_id = filterId;
			data.table = options.table;
			data.filter = options.filter || 'sys_id!=NULL';
			data.title = options.title;
			data.o = options.order_by || 'created';
			data.d = options.order_direction || 'DESC';
			data.field_list = options.field_list || '';
		}
		data.filter = _getFunctionReplaceFilter(data.filter);
	}

	function _loadFilterParams(filterId){
		var filterParams;

		var gr_portal_filter = new GlideRecord('x_153465_discovert_tasker_filters');
		if(gr_portal_filter.get(filterId)){
			filterParams = {
				tasker_filter_id: gr_portal_filter.getUniqueValue(),
				table:  gr_portal_filter.getDisplayValue('u_table.name'),
				filter: gr_portal_filter.getDisplayValue('u_filter'),
				title: gr_portal_filter.getDisplayValue('u_filter_label'),
				filter_label: gr_portal_filter.getDisplayValue('u_filter_label'),
				o: gr_portal_filter.getDisplayValue('u_order_by'),
				d: gr_portal_filter.getDisplayValue('u_direction'),
				field_list: gr_portal_filter.getDisplayValue('u_field_list') + ''
			};
		}
		return filterParams;
	}

	// get the count for the filter
	function _getDataCount() {
		var count = 0;
		var a = new GlideAggregate(data.table);
		a.addEncodedQuery(data.filter);
		a.addAggregate("COUNT");
		a.query();

		if(a.next()){
			count = a.getAggregate("COUNT");
		}
		return count;
	}

	function _loadDynamicFilter(selected_Filter_id){
		data.is_dynamic_filter = false;
		if(options.is_dynamic_filter == true || options.is_dynamic_filter == "true"){
			data.is_dynamic_filter = true;
			data.ellipsesIcon = _loadEllipsesFilterIcon();

			// STRY0113382 - reorganized and moved the loading of filters up so we could set the default to the user if one existed
			// DFCT0010732
			data.filters = _loadFilters(data.page_filter, selected_Filter_id);

		}			
	}

	function _getFilterMenuHeaderPosition(taskerFilters, menuHeader) {
		var position = -1;

		for (var i = 0; i < taskerFilters.length; i++) {
			if (taskerFilters[i].header == menuHeader) {
				position = i;
				break;
			}
		}

		return position;
	}

	function _loadEllipsesFilterIcon(){
		var icon = {src: "", title: "", alt: ""};
		var title = gs.getMessage("Tasker - Show More Filters")
		icon.src = "EllipsesMenu32.svg";
		icon.title = title;
		icon.alt = title;			
		return icon;
	}
	function _getIcon(iconId){
		var iconName = "";
		var gr_Image = new GlideRecord("db_image");
		if(gr_Image.get(iconId)){
			iconName = gr_Image.getValue("name");
		}
		return iconName;
	}

	function _loadFilters(pageFilter, selected_Filter_id) {
		taskerFilters = [];
		// 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
		// Get an array filled with the Filter Menu Headers to use in the Filter More options
		var gr_filterMenuHeaders = new GlideRecord('sys_choice');
		gr_filterMenuHeaders.addQuery('name', 'x_153465_discovert_tasker_filters');
		gr_filterMenuHeaders.addQuery('element', 'u_filter_menu_header');
		gr_filterMenuHeaders.addQuery('inactive', 'false');
		gr_filterMenuHeaders.orderBy('sequence');
		gr_filterMenuHeaders.query();

		while (gr_filterMenuHeaders.next()) {
			var menuItem = {
				header: gr_filterMenuHeaders.getDisplayValue(),
				subMenus: []
			};

			taskerFilters.push(menuItem);
		}

		// get filter from filters table
		// STRY0101803 - had to change to glide record as some users couldn't see the Table field
		var gr_filters = new GlideRecord('x_153465_discovert_tasker_filters');
		gr_filters.addQuery('u_active', true);
		gr_filters.addQuery('u_filter_page', pageFilter);
		gr_filters.addQuery('u_show_in_filter_menu', true);

		gr_filters.orderBy('u_order');
		gr_filters.orderBy('u_filter_label');
		gr_filters.query();

		while (gr_filters.next()) {
			// STRY0099083
			var currentFilter = gr_filters.getDisplayValue('u_filter');
			currentFilter = _getFunctionReplaceFilter(currentFilter);
			// STRY0108629
			var DiscoverControllerURL = gr_filters.getValue('u_discover_controller_url');
			DiscoverControllerURL = DiscoverControllerURL != null ? (DiscoverControllerURL == true) : false;

			// 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
			// Create the filter then push later
			var filter = {
				tasker_filter_id: gr_filters.getUniqueValue(),
				table: gr_filters.getDisplayValue('u_table.name'),
				// STRY0101803
				field_list: gr_filters.getDisplayValue('u_field_list') + '',
				modal_title_fields: gr_filters.getDisplayValue('u_modal_title_fields') + '',
				modal_title_field_separator: gr_filters.getDisplayValue('u_modal_title_field_separator') + '',
				// STRY0101803 load the "hover over field" from the filter defnition if set
				hoverField: gr_filters.getDisplayValue('u_hover_field') + '',
				filter_label: gr_filters.getDisplayValue('u_filter_label'),
				filter: currentFilter,
				view_all_page: gr_filters.getDisplayValue('u_view_all_page'),
				// STRY0101803
				// 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
				// include_comments: gr_filters.getDisplayValue('u_include_comments'),
				include_comments: gr_filters.getValue('u_include_comments'),
				// STRY0108629
				DiscoverControllerURL: DiscoverControllerURL,
				o: gr_filters.getDisplayValue('u_order_by'),
				d: gr_filters.getDisplayValue('u_direction')
			};

			// 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
			// Need the array element to push subMenus onto the Filter Menu Header
			var position = -1;
			if (gr_filters.getDisplayValue('u_filter_menu_header') != undefined) {
				position = _getFilterMenuHeaderPosition(taskerFilters, gr_filters.getDisplayValue('u_filter_menu_header'));
			}

			// 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
			// 2.7.0 | 2021-08-23 | mmcc | DFCT0010441 - On the Modern Portal in the filter menu "-- None --" text displays
			// update subMenus if the Filter Menu Header exists
			// if position = -1 then check the Filter Menu Header dropdown on Modern Portal Views or Choices table
			if (position > -1) {
				taskerFilters[position].subMenus.push(filter);
			}

			// set flag that the selected filter is in the curent dynamic filter
			if(filter.tasker_filter_id == selected_Filter_id){
				data.filterInDynamicList = true;
			}
		}
		// get task count for filter menu
		// 2.7.0 | 08.06.2021 | mmcc | STRY0106157 - PPM – Modern Portal – New Filter Design
		// Use forEach to get the counts
		taskerFilters.forEach(function(menuItem) {
			menuItem.subMenus.forEach(function(subMenu) {
				var count = new GlideAggregate(subMenu.table);
				count.addEncodedQuery(subMenu.filter);
				count.addAggregate('COUNT');
				count.query();
				if (count.next()) {
					subMenu.count = count.getAggregate('COUNT');
				}
			});
		});
		return taskerFilters;
	}

	function _getFunctionReplaceFilter(originalFilter){
		var updatedFilter = originalFilter;
					// DFCT0010732
			if (originalFilter.indexOf("OUsWhereIamAMemberAdmin") > 0) {
				updatedFilter = originalFilter.replace("OUsWhereIamAMemberAdmin", OUsWhereIamAMemberAdmin);
			}
			// DFCT0011947
			if (originalFilter.indexOf("OUsWhereIamAMember") > 0) {
				updatedFilter = originalFilter.replace("OUsWhereIamAMember", OUsWhereIamAMember.join(","));
			}

		return updatedFilter;

	}
})($sp, input, data, options, gs);
